import { SafeAreaView } from 'react-native-safe-area-context';
import styled, { css } from 'styled-components/native';

import { ContainerProps } from './Models';

export const Container = styled(SafeAreaView).attrs<ContainerProps>(() => ({
  edges: [
    'top',
    'left',
    'right',
  ] as const,
}))<ContainerProps>`
  flex: 1;

  ${({ theme, bgColor }) => css`
    background: ${theme.colors[bgColor as never]};
  `}
`;

export const Overlay = styled.View`
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background-color: rgba(0, 0, 0, 0.6);
  z-index: 10;
  pointer-events: auto;
`;

const globals = require('globals');
const prettierConfig = require('eslint-config-prettier/prettier');
const tseslint = require('typescript-eslint');
const reactPlugin = require('eslint-plugin-react');
const reactHooksPlugin = require('eslint-plugin-react-hooks');
const reactNativePlugin = require('eslint-plugin-react-native');
const importPlugin = require('eslint-plugin-import');
const jestPlugin = require('eslint-plugin-jest');

module.exports = [
  {
    ignores: [
      'node_modules/',
      '__tests__/coverage/',
      'babel.config.js',
      'metro.config.js',
      'jest-setup.js',
      '.eslintcache',
      '**/*.d.ts',
      './src/**/*.js',
    ],
  },
  {
    files: [
      'src/**/*.{js,mjs,cjs,ts,jsx,tsx}',
      './App.js',
      './index.js',
    ],
    languageOptions: {
      ecmaVersion: 'latest',
      sourceType: 'module',
      parser: tseslint.parser,
      parserOptions: {
        project: './tsconfig.json',
        tsconfigRootDir: __dirname,
      },
      globals: {
        'react-native/react-native': true,
      },
    },
    plugins: {
      react: reactPlugin,
      'react-hooks': reactHooksPlugin,
      '@typescript-eslint': tseslint.plugin,
      import: importPlugin,
      'react-native': reactNativePlugin,
    },
    settings: {
      'import/ignore': ['~/*'],
      'import/external-module-folders': [
        'node_modules',
        'node_modules/@types',
      ],
      'import/resolver': {
        typescript: {
          project: './tsconfig.json',
        },
        node: {
          extensions: [
            '.js',
            '.jsx',
            '.ts',
            '.tsx',
          ],
        },
      },
      'import/parsers': {
        '@typescript-eslint/parser': [
          '.ts',
          '.tsx',
        ],
      },
      react: { version: 'detect' },
    },
    rules: {
      '@typescript-eslint/no-use-before-define': [
        'error',
        {
          functions: false,
          classes: false,
          variables: true,
        },
      ],
      'import/no-extraneous-dependencies': [
        'error',
        {
          devDependencies: true,
          peerDependencies: true,
        },
      ],
      'react/jsx-filename-extension': [
        'error',
        { extensions: ['.tsx'] },
      ],
      'import/no-unresolved': [
        'error',
        { ignore: ['^~/.*'] },
      ],
      '@typescript-eslint/no-unused-vars': [
        'error',
        {
          argsIgnorePattern: '^_',
          varsIgnorePattern: '^_',
          caughtErrorsIgnorePattern: '^_',
        },
      ],
      'react-hooks/exhaustive-deps': 'error',
      'react-native/no-inline-styles': 'warn',
    },
  },
  {
    files: ['./__tests__/**/*.{js,ts,jsx,tsx}'],
    languageOptions: {
      ecmaVersion: 'latest',
      sourceType: 'module',
      parser: tseslint.parser,
      parserOptions: {
        project: './tsconfig.json',
        tsconfigRootDir: __dirname,
      },
      globals: {
        ...globals.jest,
      },
    },
    plugins: {
      jest: jestPlugin,
      import: importPlugin,
    },
    rules: {
      'import/no-extraneous-dependencies': 'off',
      '@typescript-eslint/no-var-requires': 'off',
      'global-require': 'off',
    },
  },
  {
    files: [
      // legacy jsx code
      'src/**/*.js',
      'App.js',
      'index.js',
    ],
    rules: {
      'react/jsx-filename-extension': [
        'error',
        {
          extensions: [
            '.js',
            '.jsx',
            '.tsx',
          ],
        },
      ],
    },
  },
  prettierConfig,
];

