   275→**Slice example**
   276→
   277→```ts
   278→import type { StateCreator } from 'zustand';
   279→import type { AuthActions, AuthState } from '../models/store';
   280→
   281→export type AuthSlice = {
   282→  auth: AuthState;
   283→  authActions: AuthActions;
   284→};
   285→
   286→const initialAuth = {
   287→  user: null,
   288→  loading: false,
   289→  error: undefined,
   290→};
   291→
   292→export const createAuthSlice: StateCreator<
   293→  AuthSlice,
   294→  [],
   295→  [],
   296→  AuthSlice
   297→> = set => ({
   298→  auth: initialAuth,
   299→  authActions: {
   300→    setLoading: v =>
   301→      set(s => ({
   302→        auth: {
   303→          ...s.auth,
   304→          isLoading: v,
   305→        },
   306→      })),
   307→    setUser: v =>
   308→      set(s => ({
   309→        auth: {
   310→          ...s.auth,
   311→          user: v,
   312→        },
   313→      })),
   314→    setError: v =>
   315→      set(s => ({
   316→        auth: {
   317→          ...s.auth,
   318→          error: v,
   319→        },
   320→      })),
   321→    reset: () => set({ auth: initialAuth }),
   322→  },
   323→});
   324→```
